import React, { useEffect, useState } from 'react';
import logo from '../assets/logo.png';
import './Nav.css';

const links = [
  { href: '#hello', label: 'Hello' },
  { href: '#about', label: 'About' },
  { href: '#volunteers', label: 'Team' },
  { href: '#involvement', label: 'Involvement' },
  { href: '#letter', label: 'Letter' },
  { href: '#priorities', label: 'Priorities' },
  { href: '#hobbies', label: 'Hobbies' },
  { href: '#letstalk', label: "Let's Talk" },
];

export default function Nav() {
  const [scrolled, setScrolled] = useState(false);
  const [hovered, setHovered] = useState(null);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

return (
  <nav className={`nav ${scrolled ? 'scrolled' : ''}`}>
    <a href="#hello" className="nav-logo">
      <img src={logo} alt="Shannon For A.S. Vice President" />
    </a>
    <ul className="nav-links">
      {links.map((l) => (
        <li key={l.href}>
          <a
            href={l.href}
            className={`nav-bubble ${hovered === l.href ? 'active' : ''}`}
            onMouseEnter={() => setHovered(l.href)}
            onMouseLeave={() => setHovered(null)}
          >
            <span className="bubble-bg" />
            <span className="bubble-label">{l.label}</span>
          </a>
        </li>
      ))}
      </ul>
    </nav>
  );
}
